import { supabase } from "./firebase";
import { uploadImageToImgBB } from "./imgbb";

export interface Message {
  id: string;
  sender: string;
  senderName: string;
  text?: string;
  photoUrl?: string;
  timestamp: number;
  type: "text" | "sticker" | "voice" | "call" | "photo";
  stickerId?: string;
  voiceData?: { duration: number; url: string };
  callDuration?: number;
  reactions?: { [emoji: string]: string[] };
  isEdited?: boolean;
  editedAt?: number;
  isRead?: boolean;
  readAt?: number;
  replyTo?: {
    messageId: string;
    senderName: string;
    text: string;
  };
  isFavorite?: boolean;
  isPinned?: boolean;
}

export interface Chat {
  id: string;
  name: string;
  type: "private" | "group" | "channel" | "favorites";
  createdAt: number;
  members: string[];
  messages: Message[];
  avatarUrl?: string;
}

export const createChat = async (
  chatName: string,
  chatType: "private" | "group" | "channel",
  members: string[]
) => {
  try {
    const { data, error } = await supabase
      .from("chats")
      .insert({
        name: chatName,
        is_group: chatType !== "private",
        created_at: new Date().toISOString(),
      })
      .select();

    if (error) throw error;
    return data?.[0]?.id;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const sendMessage = async (
  chatId: string,
  sender: string,
  senderName: string,
  text: string,
  replyTo?: { messageId: string; senderName: string; text: string }
) => {
  try {
    // Вставляем сообщение
    const { data: messageData, error: messageError } = await supabase
      .from("messages")
      .insert({
        chat_id: chatId,
        user_id: sender,
        content: text,
        message_type: "text",
        created_at: new Date().toISOString(),
      })
      .select()
      .single();

    if (messageError) {
      console.error("Send message error:", messageError);
      throw messageError;
    }

    // Если есть reply, создаём связь
    if (replyTo && messageData) {
      const { error: replyError } = await supabase
        .from("message_replies")
        .insert({
          message_id: messageData.id,
          reply_to_message_id: replyTo.messageId,
        });

      if (replyError) {
        console.error("Reply error:", replyError);
      }
    }

    return messageData;
  } catch (error: any) {
    console.error("Send message exception:", error);
    throw new Error(error.message || "Ошибка отправки сообщения");
  }
};

export const getMessages = async (chatId: string): Promise<Message[]> => {
  try {
    // Получаем сообщения
    const { data: messagesData, error: messagesError } = await supabase
      .from("messages")
      .select("*")
      .eq("chat_id", chatId)
      .is("deleted_at", null)
      .order("created_at", { ascending: true });

    if (messagesError) throw messagesError;

    if (!messagesData || messagesData.length === 0) return [];

    // Получаем информацию об авторах
    const userIds = [...new Set(messagesData.map((m) => m.user_id))];
    const { data: usersData } = await supabase
      .from("users")
      .select("id, username")
      .in("id", userIds);

    const usersMap = new Map(usersData?.map((u) => [u.id, u.username]) || []);

    // Получаем избранные сообщения текущего пользователя
    const { data: { user } } = await supabase.auth.getUser();
    const { data: favoritesData } = await supabase
      .from("favorites")
      .select("message_id")
      .eq("user_id", user?.id || "");

    const favoritesSet = new Set(favoritesData?.map((f) => f.message_id) || []);

    // Получаем закреплённые сообщения
    const { data: pinnedData } = await supabase
      .from("pinned_messages")
      .select("message_id")
      .eq("chat_id", chatId);

    const pinnedSet = new Set(pinnedData?.map((p) => p.message_id) || []);

    // Получаем реакции
    const { data: reactionsData } = await supabase
      .from("reactions")
      .select("message_id, emoji, user_id")
      .in("message_id", messagesData.map((m) => m.id));

    const reactionsMap = new Map<string, { [emoji: string]: string[] }>();
    reactionsData?.forEach((r) => {
      if (!reactionsMap.has(r.message_id)) {
        reactionsMap.set(r.message_id, {});
      }
      const reactions = reactionsMap.get(r.message_id)!;
      if (!reactions[r.emoji]) {
        reactions[r.emoji] = [];
      }
      reactions[r.emoji].push(r.user_id);
    });

    // Получаем информацию об ответах
    const { data: repliesData } = await supabase
      .from("message_replies")
      .select("message_id, reply_to_message_id")
      .in("message_id", messagesData.map((m) => m.id));

    const repliesMap = new Map(
      repliesData?.map((r) => [r.message_id, r.reply_to_message_id]) || []
    );

    // Получаем сообщения, на которые ответили
    const replyToIds = Array.from(repliesMap.values());
    const { data: replyToMessagesData } = await supabase
      .from("messages")
      .select("id, content, user_id")
      .in("id", replyToIds);

    const replyToMessagesMap = new Map(
      replyToMessagesData?.map((m) => [
        m.id,
        { text: m.content, userId: m.user_id },
      ]) || []
    );

    // Преобразуем в Message[]
    return messagesData.map((msg) => {
      const replyToId = repliesMap.get(msg.id);
      const replyToMsg = replyToId ? replyToMessagesMap.get(replyToId) : null;

      return {
        id: msg.id,
        sender: msg.user_id,
        senderName: usersMap.get(msg.user_id) || "Unknown",
        text: msg.content,
        timestamp: new Date(msg.created_at).getTime(),
        type: msg.message_type || "text",
        photoUrl: msg.media_url,
        voiceData:
          msg.message_type === "voice"
            ? { duration: 0, url: msg.media_url }
            : undefined,
        reactions: reactionsMap.get(msg.id),
        isFavorite: favoritesSet.has(msg.id),
        isPinned: pinnedSet.has(msg.id),
        replyTo: replyToMsg
          ? {
              messageId: replyToId,
              senderName: usersMap.get(replyToMsg.userId) || "Unknown",
              text: replyToMsg.text || "[сообщение]",
            }
          : undefined,
      };
    });
  } catch (error: any) {
    console.error("Get messages error:", error);
    throw new Error(error.message || "Ошибка загрузки сообщений");
  }
};

export const listenToMessages = (
  chatId: string,
  callback: (messages: Message[]) => void
) => {
  const subscription = supabase
    .channel(`messages:${chatId}`)
    .on(
      "postgres_changes",
      {
        event: "*",
        schema: "public",
        table: "messages",
        filter: `chat_id=eq.${chatId}`,
      },
      () => {
        getMessages(chatId).then(callback);
      }
    )
    .subscribe();

  return () => {
    subscription.unsubscribe();
  };
};

