export const getFavoriteMessages = async (
  userId: string,
  chatId: string
): Promise<Message[]> => {
  try {
    const { data: favoritesData, error: favoritesError } = await supabase
      .from("favorites")
      .select("message_id")
      .eq("user_id", userId);

    if (favoritesError) throw favoritesError;

    if (!favoritesData || favoritesData.length === 0) return [];

    const messageIds = favoritesData.map((f) => f.message_id);

    const { data: messagesData, error: messagesError } = await supabase
      .from("messages")
      .select("*")
      .in("id", messageIds)
      .eq("chat_id", chatId)
      .order("created_at", { ascending: true });

    if (messagesError) throw messagesError;

    // Получаем информацию об авторах
    const userIds = [...new Set(messagesData?.map((m) => m.user_id) || [])];
    const { data: usersData } = await supabase
      .from("users")
      .select("id, username")
      .in("id", userIds);

    const usersMap = new Map(usersData?.map((u) => [u.id, u.username]) || []);

    return (
      messagesData?.map((msg) => ({
        id: msg.id,
        sender: msg.user_id,
        senderName: usersMap.get(msg.user_id) || "Unknown",
        text: msg.content,
        timestamp: new Date(msg.created_at).getTime(),
        type: msg.message_type || "text",
        photoUrl: msg.media_url,
        isFavorite: true,
      })) || []
    );
  } catch (error: any) {
    console.error("Get favorite messages error:", error);
    throw new Error(error.message || "Ошибка загрузки избранных");
  }
};

