import { supabase } from "./firebase";
import { uploadImageToImgBB } from "./imgbb";

export const registerUser = async (email: string, password: string, username: string, userId: string) => {
  try {
    // Проверяем что userId не занят
    const { data: existingUser } = await supabase
      .from("users")
      .select("id")
      .eq("username", userId)
      .single();

    if (existingUser) {
      throw new Error("Этот ID уже занят");
    }

    // Регистрируем пользователя в auth
    const { data, error } = await supabase.auth.signUp({
      email,
      password,
    });

    if (error) throw error;

    const user = data.user;
    if (!user) throw new Error("Ошибка создания пользователя");

    // Сохраняем профиль в БД
    const { error: insertError } = await supabase.from("users").insert({
      id: user.id,
      email,
      username: username,
      avatar_url: null,
    });

    if (insertError) throw insertError;

    return user;
  } catch (error: any) {
    let message = "Ошибка регистрации";

    if (error.message.includes("already registered")) {
      message = "Этот email уже зарегистрирован";
    } else if (error.message.includes("password")) {
      message = "Пароль слишком слабый (минимум 6 символов)";
    } else if (error.message.includes("invalid email")) {
      message = "Неверный формат email";
    } else if (error.message === "Этот ID уже занят") {
      message = "Этот ID уже занят";
    } else {
      message = error.message;
    }

    throw new Error(message);
  }
};

export const loginUser = async (email: string, password: string) => {
  try {
    const { data, error } = await supabase.auth.signInWithPassword({
      email,
      password,
    });

    if (error) throw error;

    return data.user;
  } catch (error: any) {
    let message = "Ошибка входа";

    if (error.message.includes("Invalid login credentials")) {
      message = "Неверный email или пароль";
    } else if (error.message.includes("too many requests")) {
      message = "Слишком много попыток входа. Попробуйте позже";
    } else {
      message = error.message;
    }

    throw new Error(message);
  }
};

export const logoutUser = async () => {
  try {
    const { error } = await supabase.auth.signOut();
    if (error) throw error;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const getCurrentUser = async () => {
  try {
    const { data } = await supabase.auth.getSession();
    return data.session?.user || null;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const getUserProfile = async (userId: string) => {
  try {
    const { data, error } = await supabase
      .from("users")
      .select("*")
      .eq("id", userId)
      .single();

    if (error) throw error;
    return data;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const getUserUsername = async (userId: string): Promise<string> => {
  try {
    const profile = await getUserProfile(userId);
    return profile?.username || "Unknown";
  } catch (error: any) {
    return "Unknown";
  }
};

export const updateUserProfile = async (
  userId: string,
  username: string,
  userIdDisplay?: string,
  avatarUrl?: string,
  isHidden?: boolean
) => {
  try {
    const updates: any = { username };
    if (avatarUrl) {
      updates.avatar_url = avatarUrl;
    }

    const { error } = await supabase
      .from("users")
      .update(updates)
      .eq("id", userId);

    if (error) throw error;
  } catch (error: any) {
    throw new Error(error.message || "Ошибка обновления профиля");
  }
};

export const uploadAvatar = async (userId: string, file: File) => {
  try {
    const avatarUrl = await uploadImageToImgBB(file);

    const { error } = await supabase
      .from("users")
      .update({ avatar_url: avatarUrl })
      .eq("id", userId);

    if (error) throw error;
    return avatarUrl;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const blockUser = async (userId: string, blockedUserId: string) => {
  try {
    const { error } = await supabase
      .from("blocked_users")
      .insert({ user_id: userId, blocked_user_id: blockedUserId });

    if (error) throw error;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const unblockUser = async (userId: string, blockedUserId: string) => {
  try {
    const { error } = await supabase
      .from("blocked_users")
      .delete()
      .eq("user_id", userId)
      .eq("blocked_user_id", blockedUserId);

    if (error) throw error;
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const getBlockedUsers = async (userId: string) => {
  try {
    const { data, error } = await supabase
      .from("blocked_users")
      .select("blocked_user_id")
      .eq("user_id", userId);

    if (error) throw error;
    return data?.map((item) => item.blocked_user_id) || [];
  } catch (error: any) {
    throw new Error(error.message);
  }
};

export const isUserBlocked = async (
  userId: string,
  otherUserId: string
) => {
  try {
    const { data, error } = await supabase
      .from("blocked_users")
      .select("id")
      .eq("user_id", userId)
      .eq("blocked_user_id", otherUserId)
      .single();

    if (error && error.code !== "PGRST116") throw error;
    return !!data;
  } catch (error: any) {
    return false;
  }
};
